-- Migration 004: Add nullable user_id to all tables (prep for auth)
-- user_id is nullable so existing data is not broken.
-- RLS policies are NOT changed yet — still allow all.
-- Do NOT run this until you are ready to integrate Supabase Auth.

-- books
ALTER TABLE books
  ADD COLUMN IF NOT EXISTS user_id UUID;

-- quotes
ALTER TABLE quotes
  ADD COLUMN IF NOT EXISTS user_id UUID;

-- book_notes
ALTER TABLE book_notes
  ADD COLUMN IF NOT EXISTS user_id UUID;

-- connections (create the table first if it doesn't exist yet;
-- if it already exists in your DB, only the ALTER TABLE line is needed)
CREATE TABLE IF NOT EXISTS connections (
  id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id    UUID,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- If the table already exists and just needs the column:
ALTER TABLE connections
  ADD COLUMN IF NOT EXISTS user_id UUID;

-- Optional: index each user_id for future query performance
CREATE INDEX IF NOT EXISTS idx_books_user_id       ON books(user_id);
CREATE INDEX IF NOT EXISTS idx_quotes_user_id      ON quotes(user_id);
CREATE INDEX IF NOT EXISTS idx_book_notes_user_id  ON book_notes(user_id);
CREATE INDEX IF NOT EXISTS idx_connections_user_id ON connections(user_id);

-- Migration 006: Fix INSERT RLS on all user-scoped tables
--
-- Problem: the FOR ALL policy uses WITH CHECK (auth.uid() = user_id), but
-- API routes never pass user_id in INSERT payloads, so the column stays NULL
-- and the check fails.
--
-- Fix: set DEFAULT auth.uid() on each user_id column so Postgres stamps it
-- automatically on every INSERT. The existing WITH CHECK policy then passes
-- because the default makes user_id equal to auth.uid() at insert time.

ALTER TABLE books          ALTER COLUMN user_id SET DEFAULT auth.uid();
ALTER TABLE quotes         ALTER COLUMN user_id SET DEFAULT auth.uid();
ALTER TABLE book_notes     ALTER COLUMN user_id SET DEFAULT auth.uid();
ALTER TABLE connections    ALTER COLUMN user_id SET DEFAULT auth.uid();
ALTER TABLE quote_headings ALTER COLUMN user_id SET DEFAULT auth.uid();

