@import "tailwindcss";

@theme inline {
  --font-sans: var(--font-geist);
  --font-serif: var(--font-lora);
}

@theme {
  /* Fog — light blue-gray scale */
  --color-fog-50:  #f8fafc;
  --color-fog-100: #f1f5f9;
  --color-fog-200: #e8edf2;   /* page background */
  --color-fog-300: #dde4ed;   /* card borders, dividers */
  --color-fog-400: #c2cedb;   /* muted borders */
  --color-fog-500: #8fa5bc;   /* muted text */
  --color-fog-600: #637d97;   /* secondary text */
  --color-fog-700: #445d73;   /* dark secondary */

  /* Navy — deep blue scale */
  --color-navy-50:  #eef2f7;
  --color-navy-100: #d5e0ed;
  --color-navy-200: #adc2d9;
  --color-navy-300: #7aa0c0;
  --color-navy-400: #4a7fa8;
  --color-navy-500: #2d6090;
  --color-navy-600: #1e4a7a;
  --color-navy-700: #1a3a6b;   /* primary headings, primary button */
  --color-navy-800: #142d55;
  --color-navy-900: #0d1e35;   /* darkest text */

  /* Ember — deep amber scale */
  --color-ember-50:  #fdf4e7;
  --color-ember-100: #fae3c0;
  --color-ember-200: #f4c98a;
  --color-ember-300: #e8a83e;
  --color-ember-400: #d4881a;
  --color-ember-500: #c47209;   /* primary amber */
  --color-ember-600: #b5620a;
  --color-ember-700: #8f4c08;

  /* Accent singletons */
  --color-midnight:     #191970;  /* midnight blue — main heading */
  --color-forest:       #2d6a4f;  /* forest green — progress bars */
  --color-burnt-orange: #cc5500;  /* burnt orange — section headings */
}

*, *::before, *::after {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-sans), system-ui, sans-serif;
  background-color: #e8edf2;
}

/* Thin, unobtrusive scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background-color: #c2cedb;
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background-color: #8fa5bc;
}

