import { NextRequest } from 'next/server'
import Stripe from 'stripe'
import { createSupabaseServerClient } from '@/lib/supabase-server'
import { createSupabaseAdminClient } from '@/lib/supabase-admin'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!)

const PRICE_IDS: Record<string, string | undefined> = {
  monthly: process.env.STRIPE_MONTHLY_PRICE_ID,
  annual:  process.env.STRIPE_ANNUAL_PRICE_ID,
}

export async function POST(req: NextRequest) {
  const supabase = await createSupabaseServerClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 })

  const body = await req.json()
  const plan: 'monthly' | 'annual' = body.plan === 'monthly' ? 'monthly' : 'annual'
  const priceId = PRICE_IDS[plan]
  if (!priceId) {
    return Response.json({ error: `Price ID for "${plan}" is not configured` }, { status: 500 })
  }

  const admin = createSupabaseAdminClient()

  // Get or create Stripe customer
  const { data: profile } = await admin
    .from('profiles')
    .select('stripe_customer_id')
    .eq('id', user.id)
    .single()

  let customerId = profile?.stripe_customer_id ?? null

  if (!customerId) {
    const customer = await stripe.customers.create({
      email: user.email,
      metadata: { supabase_user_id: user.id },
    })
    customerId = customer.id
    await admin.from('profiles').upsert({ id: user.id, stripe_customer_id: customerId })
  }

  const origin = req.headers.get('origin') ?? 'http://localhost:3000'

  const session = await stripe.checkout.sessions.create({
    customer: customerId,
    mode: 'subscription',
    line_items: [{ price: priceId, quantity: 1 }],
    metadata: { supabase_user_id: user.id },
    subscription_data: {
      metadata: { supabase_user_id: user.id },
    },
    success_url: `${origin}/home?subscribed=true`,
    cancel_url:  `${origin}/pricing`,
    allow_promotion_codes: true,
  })

  return Response.json({ url: session.url })
}

