          <p className="text-fog-600 text-lg max-w-md mx-auto">
            Start free. Upgrade when you need more room to grow.
          </p>
        </div>

        {/* Billing toggle */}
        <div className="flex justify-center mb-10">
          <div className="flex items-center gap-1 bg-white border border-fog-300 rounded-full p-1 shadow-sm">
            <button
              onClick={() => setBilling('monthly')}
              className={`px-5 py-2 rounded-full text-sm font-medium transition-all ${
                billing === 'monthly'
                  ? 'bg-navy-700 text-white shadow-sm'
                  : 'text-fog-600 hover:text-navy-700'
              }`}
            >
              Monthly
            </button>
            <button
              onClick={() => setBilling('annual')}
              className={`px-5 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${
                billing === 'annual'
                  ? 'bg-navy-700 text-white shadow-sm'
                  : 'text-fog-600 hover:text-navy-700'
              }`}
            >
