  'Cross-book PDF export',
  'Priority support',
]

const ANNUAL_FEATURES = [
  'Everything in Pro',
  'Save 17% vs monthly',
  'Billed once a year',
]

function CheckIcon() {
  return (
    <svg viewBox="0 0 16 16" fill="currentColor" className="w-4 h-4 shrink-0">
      <path fillRule="evenodd" d="M12.416 3.376a.75.75 0 0 1 .208 1.04l-5 7.5a.75.75 0 0 1-1.154.114l-3-3a.75.75 0 0 1 1.06-1.06l2.353 2.353 4.493-6.74a.75.75 0 0 1 1.04-.207Z" clipRule="evenodd" />
    </svg>
  )
}

export default function PricingPage() {
  const router = useRouter()
  const [isPro, setIsPro]   = useState(false)
  const [loadingPlan, setLoadingPlan] = useState<'monthly' | 'annual' | 'portal' | null>(null)
  const [error, setError]   = useState('')

  useEffect(() => {
    supabase.auth.getUser().then(async ({ data: { user } }) => {
      if (!user) return
      const { data } = await supabase
        .from('profiles')
        .select('subscription_status, is_comped')
        .eq('id', user.id)
        .single()
      setIsPro(data?.subscription_status === 'pro' || data?.is_comped === true)
    })
  }, [])

  async function handleSubscribe(plan: 'monthly' | 'annual') {
    setError('')
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) { router.push('/login'); return }

    setLoadingPlan(plan)
    try {
      const res  = await fetch('/api/stripe/checkout', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ plan }),
      })
      const json = await res.json()
      if (!res.ok) { setError(json.error ?? 'Something went wrong'); return }
      window.location.href = json.url
    } catch {
      setError('Network error — please try again')
    } finally {
      setLoadingPlan(null)
    }
  }

  async function handleManage() {
    setError('')
    setLoadingPlan('portal')
    try {
      const res  = await fetch('/api/stripe/portal')
      const json = await res.json()
      if (!res.ok) { setError(json.error ?? 'Something went wrong'); return }
      window.location.href = json.url
    } catch {
      setError('Network error — please try again')
    } finally {
      setLoadingPlan(null)
    }
  }

  return (
    <div className="min-h-screen bg-fog-200 flex flex-col">

      {/* ── Header ── */}
