            MindWell
          </Link>
          <Link href="/home" className="text-sm text-fog-600 hover:text-navy-700 transition-colors">
            ← Back to app
          </Link>
        </div>
      </header>

      <main className="flex-1 max-w-5xl mx-auto px-6 py-16 w-full">

        {/* ── Hero ── */}
        <div className="text-center mb-14">
          <h1 className="text-4xl font-bold tracking-tight mb-3" style={{ color: '#191970' }}>
            Find the plan that fits
          </h1>
          <p className="text-fog-600 text-lg max-w-md mx-auto leading-relaxed">
            Start free and upgrade when you&rsquo;re ready for more.
          </p>
        </div>

        {/* ── Tier cards ── */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-start">

          {/* ── Basic (free) ── */}
          <div className="bg-white rounded-2xl border border-fog-300 shadow-sm p-7 flex flex-col gap-6">
            <div>
              <p className="text-xs font-bold uppercase tracking-widest text-fog-500 mb-1">Free</p>
              <h2 className="text-xl font-bold text-navy-900">MindWell Basic</h2>
              <div className="mt-3 flex items-end gap-1">
                <span className="text-4xl font-bold text-navy-900">$0</span>
                <span className="text-fog-500 text-sm mb-1">/ forever</span>
              </div>
            </div>

            <ul className="space-y-3 flex-1">
              {BASIC_FEATURES.map(f => (
                <li key={f} className="flex items-start gap-2.5 text-sm text-navy-800">
                  <span className="text-fog-400 mt-0.5"><CheckIcon /></span>
                  {f}
                </li>
              ))}
            </ul>

            <div className="pt-1">
              {isPro ? (
                <p className="text-center text-sm text-fog-500 py-2">Your current plan</p>
              ) : (
                <Link
                  href="/home"
                  className="block w-full text-center bg-fog-100 hover:bg-fog-200 text-navy-700 px-4 py-2.5 rounded-full text-sm font-semibold transition-all"
                >
                  Get started free
                </Link>
              )}
            </div>
          </div>

