// ── Dashboard content (uses useSearchParams) ───────────────────────────────────

function DashboardContent() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { user, signOut } = useAuth()

  const [books, setBooks] = useState<Book[]>([])
  const [recentRefreshKey, setRecentRefreshKey] = useState(0)
  const [loading, setLoading] = useState(true)
  const [nextUpExpanded, setNextUpExpanded] = useState(false)
  const [activeDragBookId, setActiveDragBookId] = useState<string | null>(null)
  const [showAddItem, setShowAddItem] = useState(false)
  const [showSearch, setShowSearch] = useState(false)
  const [completeBookTarget, setCompleteBookTarget] = useState<Book | null>(null)
  const [isPro, setIsPro] = useState(true) // optimistic: avoids flash of disabled state

  // Detail modal via URL params
  const detailBookId = searchParams.get('book')
  const detailTabParam = searchParams.get('tab') ?? 'outline'
  const detailTab = (['outline', 'brainstorm', 'quotes'].includes(detailTabParam)
    ? detailTabParam
    : 'outline') as 'outline' | 'brainstorm' | 'quotes'

  function openDetail(bookId: string, tab = 'outline') {
    if (user) {
      const book = books.find(b => b.id === bookId)
      if (book) {
        trackRecentlyViewed(user.id, { id: bookId, title: book.title, type: book.type })
        setRecentRefreshKey(k => k + 1)
      }
    }
    router.push(`/home?book=${bookId}&tab=${tab}`, { scroll: false })
  }

  function closeDetail() {
    router.push('/home', { scroll: false })
  }

  const refresh = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('books')
        .select('*')
        .order('sort_order', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: false })
      if (error) throw error
      const bookList = (data as Book[]) ?? []
      cacheBooks(bookList)
      setBooks(bookList)
    } catch {
      // Offline: show cached books merged with any locally-queued creates
      const cached = getCachedBooks()
      const pending = await getPendingBooks()
      const cachedIds = new Set(cached.map((b) => b.id))
      const newPending = pending.filter((p) => !cachedIds.has(p.id))
      setBooks([...newPending, ...cached])
    }
    setLoading(false)
  }, [])

  useEffect(() => {
    refresh()
    // Check subscription status so we can enforce the free-tier limit
    supabase.auth.getUser().then(async ({ data: { user } }) => {
      if (!user) return
      const { data } = await supabase
        .from('profiles')
        .select('subscription_status, is_comped')
        .eq('id', user.id)
        .single()
      setIsPro(data?.subscription_status === 'pro' || data?.is_comped === true)
    })
  }, [refresh])

  // When connectivity is restored: drain the sync queue, then re-fetch
  useEffect(() => {
    async function handleOnline() {
      await processQueue()
      await refresh()
      window.dispatchEvent(new Event('mindwell-queue-updated'))
    }
    window.addEventListener('online', handleOnline)
    // Also respond to the PWAProvider's post-sync event
    window.addEventListener('mindwell-synced', refresh)
    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('mindwell-synced', refresh)
    }
  }, [refresh])

  // Cmd+K / Ctrl+K → open search
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setShowSearch(s => !s)
      }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [])

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  // Free-tier limit: count all non-completed items (active + queued + paused)
  const activeItemCount = books.filter(b => b.status !== 'completed').length
  const upgradeRequired = !isPro && activeItemCount >= 3

  const readingNow = books.filter(b => b.status === 'active' && b.type === 'book')
  const nextUp = books.filter(b => (b.status === 'queued' || b.status === 'paused') && b.type === 'book')
  const activeArticles = books.filter(b => b.status === 'active' && b.type === 'article')
  const activePodcasts = books.filter(b => b.status === 'active' && b.type === 'podcast')
  const completedBooks = books.filter(b => b.status === 'completed' && b.type === 'book')
  const completedArticles = books.filter(b => b.status === 'completed' && b.type === 'article')
  const completedPodcasts = books.filter(b => b.status === 'completed' && b.type === 'podcast')

  const activeDragBook = activeDragBookId
    ? books.find(b => b.id === activeDragBookId) ?? null
    : null

  async function handleMoveUp(book: Book) {
    if (readingNow.length >= 10) return
    setBooks(prev => prev.map(b =>
      b.id === book.id ? { ...b, status: 'active' } : b
    ))
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'active' }),
    })
  }

  function handleDragStart(event: DragStartEvent) {
    setActiveDragBookId(event.active.id as string)
    setNextUpExpanded(true)
  }

  async function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event
    setActiveDragBookId(null)
    if (!over) return

    const activeId = active.id as string
    const overId = over.id as string
    if (activeId === overId) return

    const inReading = readingNow.some(b => b.id === activeId)
    const inQueue = nextUp.some(b => b.id === activeId)

    const overIsReadingSection = overId === READING_SECTION
    const overIsQueueSection = overId === QUEUE_SECTION
    const overInReading = readingNow.some(b => b.id === overId)
    const overInQueue = nextUp.some(b => b.id === overId)

    let destSection: 'reading' | 'queue' | null = null
    if (overIsReadingSection || overInReading) destSection = 'reading'
    else if (overIsQueueSection || overInQueue) destSection = 'queue'
    if (!destSection) return

    const sourceSection = inReading ? 'reading' : inQueue ? 'queue' : null
    if (!sourceSection) return

    if (sourceSection === destSection) {
      const list = sourceSection === 'reading' ? readingNow : nextUp
      const oldIndex = list.findIndex(b => b.id === activeId)
      const newIndex = (overIsReadingSection || overIsQueueSection)
        ? list.length - 1
        : list.findIndex(b => b.id === overId)
      if (oldIndex === -1 || newIndex === -1 || oldIndex === newIndex) return

      const reordered = arrayMove(list, oldIndex, newIndex)
      setBooks(prev => {
        const others = prev.filter(b => !list.some(l => l.id === b.id))
        return [...others, ...reordered.map((b, i) => ({ ...b, sort_order: i + 1 }))]
      })
      await fetch('/api/books/reorder', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ orderedIds: reordered.map(b => b.id) }),
      })
      await refresh()
    } else {
      if (destSection === 'reading' && readingNow.length >= 10) return
      const originalStatus = books.find(b => b.id === activeId)?.status
      const newStatus = destSection === 'reading' ? 'active' : 'queued'

      setBooks(prev => prev.map(b =>
        b.id === activeId ? { ...b, status: newStatus } : b
      ))

      const res = await fetch(`/api/books/${activeId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      })
      if (!res.ok && originalStatus) {
        setBooks(prev => prev.map(b =>
          b.id === activeId ? { ...b, status: originalStatus } : b
        ))
      }
    }
  }

  async function handleCompleteBook(book: Book) {
    await fetch(`/api/books/${book.id}/complete`, { method: 'POST' })
    setCompleteBookTarget(null)
    await refresh()
  }

  async function handleCompleteNonBook(book: Book) {
    const today = new Date().toISOString().split('T')[0]
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed', date_finished: today }),
    })
    await refresh()
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-fog-200 flex items-center justify-center text-fog-500 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-fog-200">
      {/* Header */}
      <header className="bg-white/80 border-b border-fog-300 sticky top-0 z-10 backdrop-blur-xl">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-2xl font-bold tracking-tight" style={{ color: '#191970' }}>MindWell</h1>
          <div className="flex items-center gap-2">
            {user && (
              <RecentlyViewedDropdown
                userId={user.id}
                onOpen={id => openDetail(id)}
                refreshKey={recentRefreshKey}
              />
            )}
            <button
              onClick={() => setShowSearch(true)}
              className="text-fog-600 hover:text-navy-700 px-3 py-1.5 rounded-full bg-fog-100 hover:bg-fog-200 text-sm flex items-center gap-2 transition-all"
              title="Search (⌘K)"
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
                <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
              </svg>
              <span className="hidden sm:inline">Search</span>
              <kbd className="hidden sm:inline text-[10px] font-mono bg-fog-200 text-fog-500 px-1.5 py-0.5 rounded border border-fog-300">⌘K</kbd>
            </button>
            <div className="flex items-center gap-1.5">
              {upgradeRequired && (
                <a
                  href="/pricing"
                  className="text-xs text-ember-600 hover:text-ember-700 font-medium transition-colors hidden sm:inline"
                >
                  Upgrade for more
                </a>
              )}
              <button
                onClick={() => setShowAddItem(true)}
                disabled={upgradeRequired}
                className={`w-9 h-9 flex items-center justify-center rounded-full text-xl font-light transition-all leading-none ${
                  upgradeRequired
                    ? 'bg-fog-300 text-fog-500 cursor-not-allowed'
                    : 'bg-navy-700 hover:bg-navy-800 text-white'
                }`}
                title={upgradeRequired ? 'Upgrade to add more items' : 'Add book, article, or podcast'}
              >
                {upgradeRequired ? '🔒' : '+'}
              </button>
            </div>
            <button
              onClick={signOut}
              className="text-fog-500 hover:text-navy-700 px-2 py-1.5 rounded-full hover:bg-fog-100 text-xs transition-all"
              title="Sign out"
            >
              Sign out
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-8">
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragStart={handleDragStart}
          onDragEnd={handleDragEnd}
        >

          {/* ── Reading Now ── */}
          <section>
            <SectionHeader>📚 Reading Now</SectionHeader>
            <DroppableSection id={READING_SECTION}>
              {readingNow.length === 0 ? (
                <div className="text-center py-12 text-fog-400 bg-white rounded-xl border border-dashed border-fog-300">
                  <p className="text-sm mb-3">Nothing here yet</p>
                  <button
                    onClick={() => setShowAddItem(true)}
                    className="text-sm text-navy-600 hover:text-navy-800 font-medium transition-colors"
                  >
                    Add your first book →
                  </button>
                </div>
              ) : (
                <SortableContext items={readingNow.map(b => b.id)} strategy={verticalListSortingStrategy}>
                  <div className="space-y-2">
                    {readingNow.map(book => (
                      <SortableBookRow
                        key={book.id}
                        book={book}
                        onOpenDetail={() => openDetail(book.id)}
                        onComplete={() => setCompleteBookTarget(book)}
                      />
                    ))}
                  </div>
                </SortableContext>
              )}
            </DroppableSection>
          </section>

          {/* ── Articles ── */}
          {activeArticles.length > 0 && (
            <section>
              <SectionHeader>📰 Articles</SectionHeader>
              <div className="space-y-2">
                {activeArticles.map(article => (
                  <ArticleCard
                    key={article.id}
                    book={article}
                    onOpenDetail={() => openDetail(article.id)}
                    onDone={() => handleCompleteNonBook(article)}
                  />
                ))}
              </div>
            </section>
          )}

          {/* ── Podcasts ── */}
          {activePodcasts.length > 0 && (
            <section>
              <SectionHeader>🎙️ Podcasts</SectionHeader>
              <div className="space-y-2">
                {activePodcasts.map(podcast => (
                  <PodcastCard
                    key={podcast.id}
                    book={podcast}
                    onOpenDetail={() => openDetail(podcast.id)}
                    onDone={() => handleCompleteNonBook(podcast)}
                  />
                ))}
              </div>
            </section>
          )}

          {/* ── Next Up ── */}
          <section>
            <DroppableSection id={QUEUE_SECTION}>
              <button
                onClick={() => setNextUpExpanded(e => !e)}
                className="flex items-center gap-2 mb-3 group"
              >
                <h2 className="text-[11px] font-bold uppercase tracking-widest text-[#cc5500] group-hover:text-[#b84a00] transition-colors">
                  Next Up
                </h2>
                <span className="text-fog-400 text-xs group-hover:text-fog-600 transition-colors">
                  {nextUp.length > 0 ? `(${nextUp.length}) ` : ''}{nextUpExpanded ? '▾' : '▸'}
                </span>
              </button>

              {nextUpExpanded && (
                nextUp.length === 0 ? (
                  <div className="text-center py-8 text-fog-400 bg-white rounded-xl border border-dashed border-fog-300 text-sm">
                    Drag books here from Reading Now
                  </div>
                ) : (
                  <SortableContext items={nextUp.map(b => b.id)} strategy={verticalListSortingStrategy}>
                    <div className="space-y-2">
                      {nextUp.map(book => (
                        <SortableBookRow
                          key={book.id}
                          book={book}
                          onOpenDetail={() => openDetail(book.id)}
                          onComplete={() => setCompleteBookTarget(book)}
                          onMoveUp={() => handleMoveUp(book)}
                          showEmoji
                        />
                      ))}
                    </div>
                  </SortableContext>
                )
              )}
            </DroppableSection>
          </section>

          <DragOverlay dropAnimation={null}>
            {activeDragBook && <BookDragOverlay book={activeDragBook} />}
          </DragOverlay>
        </DndContext>

        {/* ── Completed Media ── */}
        <CompletedMediaSection
          books={completedBooks}
          articles={completedArticles}
          podcasts={completedPodcasts}
          onOpenDetail={book => openDetail(book.id)}
        />
      </main>

      {/* Modals */}
      {showAddItem && (
        <AddItemModal onClose={() => setShowAddItem(false)} onSuccess={refresh} />
      )}

      {completeBookTarget && (
        <ConfirmCompleteModal
          book={completeBookTarget}
          onClose={() => setCompleteBookTarget(null)}
          onConfirm={() => handleCompleteBook(completeBookTarget)}
        />
      )}

      {detailBookId && (
        <DetailModal
          bookId={detailBookId}
          initialTab={detailTab}
          onClose={closeDetail}
          onDelete={() => { closeDetail(); refresh() }}
          onUpdate={refresh}
        />
      )}

      {showSearch && <GlobalSearch onClose={() => setShowSearch(false)} />}
    </div>
  )
}

// ── Default export wrapped in Suspense for useSearchParams ─────────────────────

export default function Dashboard() {
  return (
    <Suspense fallback={
      <div className="min-h-screen bg-fog-200 flex items-center justify-center text-fog-500 text-sm">
        Loading…
      </div>
    }>
      <DashboardContent />
    </Suspense>
  )
}
